const batchConfig = {{node:code_node_92Bgde9z.data.batchConfig}};
const format = batchConfig.batch_format;
const effectiveDate = new Date();
let preview = format;
const is12HourFormat = format.includes("aa");

// Helper function to check if reset is needed
const needsReset = (lastResetDate, resetFrequency, currentDate) => {
  if (!lastResetDate) return true;

  const lastReset = new Date(lastResetDate);
  const currentYear = currentDate.getFullYear();
  const currentMonth = currentDate.getMonth();

  if (resetFrequency === "Reset Monthly") {
    // Check if last reset was in a different month/year
    return lastReset.getFullYear() !== currentYear || 
           lastReset.getMonth() !== currentMonth;
  } else if (resetFrequency === "Reset Yearly") {
    // Check if last reset was in a different year
    return lastReset.getFullYear() !== currentYear;
  }

  return false; // Never Reset
};

// Get the current running number to use
let currentRunningNumber = batchConfig.running_number || 0;
let needsResetFlag = false;

// Check reset frequency logic
if (batchConfig.reset_frequency === "Reset Monthly" || 
    batchConfig.reset_frequency === "Reset Yearly") {

  const needsResetValue = needsReset(
    batchConfig.last_reset_date,
    batchConfig.reset_frequency,
    effectiveDate
  );

  if (needsResetValue) {
    // Use initial_value instead of running_number
    currentRunningNumber = batchConfig.initial_value || 0;
    needsResetFlag = true;
  }
}

// Format date tokens
const dateFormats = [
  { pattern: "aa", value: effectiveDate.getHours() >= 12 ? "PM" : "AM" },
  {
    pattern: "MMMM",
    value: effectiveDate.toLocaleDateString("en-US", { month: "long" }),
  },
  {
    pattern: "dddd",
    value: effectiveDate.toLocaleDateString("en-US", { weekday: "long" }),
  },
  { pattern: "yyyy", value: effectiveDate.getFullYear().toString() },
  {
    pattern: "MMM",
    value: effectiveDate.toLocaleDateString("en-US", { month: "short" }),
  },
  {
    pattern: "ddd",
    value: effectiveDate.toLocaleDateString("en-US", { weekday: "short" }),
  },
  { pattern: "yy", value: effectiveDate.getFullYear().toString().slice(-2) },
  {
    pattern: "MM",
    value: String(effectiveDate.getMonth() + 1).padStart(2, "0"),
  },
  { pattern: "dd", value: String(effectiveDate.getDate()).padStart(2, "0") },
  {
    pattern: "hh",
    value: is12HourFormat
      ? String(effectiveDate.getHours() % 12 || 12).padStart(2, "0")
      : String(effectiveDate.getHours()).padStart(2, "0"),
  },
  { pattern: "mm", value: String(effectiveDate.getMinutes()).padStart(2, "0") },
  { pattern: "ss", value: String(effectiveDate.getSeconds()).padStart(2, "0") },
];

// Replace date patterns
dateFormats.forEach(({ pattern, value }) => {
  const regex = new RegExp(pattern, "g");
  preview = preview.replace(regex, value);
});

// Replace zero-padding patterns
const zeroPaddingMatches = format.match(/%\d+d/g) || [];
zeroPaddingMatches.forEach((padding) => {
  const length = parseInt(padding.match(/\d+/)[0]);
  const paddedNumber = String(currentRunningNumber).padStart(length, "0");
  preview = preview.replace(padding, paddedNumber);
});

// Calculate new running number (always increment by 1)
let newRunningNumber = currentRunningNumber + 1;

// If reset occurred, also update last_reset_date
let updatedLastResetDate = batchConfig.last_reset_date;
if (needsResetFlag && (batchConfig.reset_frequency === "Reset Monthly" || batchConfig.reset_frequency === "Reset Yearly")) {
  updatedLastResetDate = effectiveDate.toISOString();
}

const result = {
  id: batchConfig.id,
  preview: preview,
  running_number: newRunningNumber,
  previous_running_number: currentRunningNumber,
  reset_occurred: needsResetFlag,
  last_reset_date: updatedLastResetDate,
  generated_at: effectiveDate.toISOString()
}

return { result };

